# String utility module - provides string manipulation functions and classes

def reverse_string(s: str) -> str:
    result: str = ""
    i: int = len(s) - 1
    while i >= 0:
        result = result + str(s[i])
        i = i - 1
    return result

def is_palindrome(s: str) -> bool:
    reversed_s: str = reverse_string(s)
    return s == reversed_s

class StringBuilder:
    parts: list[str]

    def __init__(self):
        self.parts = []

    def append(self, s: str):
        self.parts.append(s)

    def to_string(self) -> str:
        result: str = ""
        for part in self.parts:
            result = result + part
        return result

    def clear(self):
        self.parts.clear()

