# Math utility module - provides mathematical functions

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    return n * factorial(n - 1)

def is_prime(n: int) -> bool:
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    i: int = 3
    while i * i <= n:
        if n % i == 0:
            return False
        i = i + 2
    return True

def sum_of_digits(n: int) -> int:
    total: int = 0
    remaining: int = n
    while remaining > 0:
        total = total + (remaining % 10)
        remaining = remaining // 10
    return total
